var e=JSON.parse(`[{"id":"L5_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"아카데미의 문화를 빛내는 자리에 함께해 주어 고맙습니다. 학우 여러분.","JPN":"生徒の皆様、\\nアカデミーの栄えある伝統的なこの場にご参加いただき、ありがとうございます。","ENG":"My fellow students, thank you for coming here to share the Academy's culture together.","TWN":"謝謝各位同學來到這裡，一起為學院的文化增添光彩。"},"stage":{"bg":"SPORTSGROUND","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"우리 아카데미에서 운동회란, 단합을 통해 학우들에게 협동정신을 심어주는 행사입니다.","JPN":"我がアカデミーにおいて運動会とは、団結することによって生徒の協同精神を養う行事です。","ENG":"The Field Day is an occasion for us to learn how to cooperate with each other.","TWN":"我們學院的運動會旨在透過團結讓同學們學習到合作精神。"},"stage":{"bg":"SPORTSGROUND","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"동시에 우승이라는 목표를 위해 선의의 경쟁과 성장을 도모하는 교육의 장이기도 하죠.","JPN":"同時に、優勝という目標のために善き競争と成長を図る教育の場でもあります。","ENG":"It's also a valuable opportunity in which we can improve ourselves through fair competition.","TWN":"同時它也是以奪冠為目標，追求善意競爭與成長的一種教育方式。"},"stage":{"bg":"SPORTSGROUND","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"그러니 부디 이 자리에서 지금까지 쌓아온 노력의 결실을 아낌없이 증명해 주시기를 바라며......","JPN":"ですから、ぜひこの場で今まで積み重ねてきた努力の成果を惜しみなく発揮していただき……","ENG":"In order to achieve these purposes, I'd like you all to make your best efforts to show your abilities...","TWN":"所以，希望大家在這裡不遺餘力地證明自己過去累積的努力成果……"},"stage":{"bg":"SPORTSGROUND","slots":{"L":null,"C":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"흐아암......","JPN":"ふわぁ～","ENG":"*Yawn*","TWN":"哈啊啊……"},"stage":{"bg":"SPORTSGROUND","slots":{"L":null,"C":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"회장...... 다들 훈화가 지루해서 죽으려고 하는 거 같아......","JPN":"会長……みんな演説がつまらなくて辛そうな顔しているよ……","ENG":"Yen... Everyone's dying because of your boring speech...","TWN":"會長……大家好像聽的有些厭煩了zzz……"},"stage":{"bg":"SPORTSGROUND","slots":{"L":null,"C":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"그래요? 저도 모르게 들떠 있었나 보네요.","JPN":"そうですか？　私もつい浮かれてしまったようですね。","ENG":"Really? I'm sorry I got carried away.","TWN":"是嗎？看來，我也在不知不覺中興奮起來了。"},"stage":{"bg":"SPORTSGROUND","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"본론으로 들어가죠. 운동회에서 모든 선수는 홍팀과 청팀으로 나뉘어 협동하고 경쟁하게 됩니다.","JPN":"本題に入りましょう。運動会ではすべての選手は赤組と青組に分かれ、協力して競うことになります。","ENG":"Let's cut to the chase. All players will be cooperating or competing on two teams: Red Team and Blue Team.","TWN":"言歸正傳，運動會上所有選手將分成紅、藍兩隊。"},"stage":{"bg":"SPORTSGROUND","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"각 경기마다 선수 각자의 개인점수와 팀 점수를 얻고, 그렇게 두 점수를 합산해 최고점을 얻은 선수가 우승하게 되죠.","JPN":"競技ごとに選手各自の個人点数とチーム点数を獲得し、\\nその2つの点数を合算して最高点を得た選手が優勝となります。","ENG":"In each game, everyone will earn both individual and team points. Whoever gets the highest total points will win the game.","TWN":"每場比賽獲得選手的個人分數和團隊分數，兩個分數加總，拿到最高分的選手獲勝。"},"stage":{"bg":"SPORTSGROUND","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"첫 번째 경기는 <color=#ffd34c>꼬리 잡기</color>.","JPN":"最初の試合は<color=#ffd34c>しっぽ取りゲーム</color>。","ENG":"The first game is called <color=#ffd34c>Catch the Tail</color>.","TWN":"第一場比賽是<color=#ffd34c>抓尾巴</color>。"},"stage":{"bg":"SPORTSGROUND","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"자세한 내용은 특별히 선별된 진행 요원이 전달해 줄 겁니다.","JPN":"詳しいルールは、この度特別に選別された進行スタッフからお伝えします。","ENG":"The special host here will tell you the details.","TWN":"具體內容將由特別邀請的主持人向大家介紹。"},"stage":{"bg":"SPORTSGROUND","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"HARIM_REBBIT_SPORTS_BG","text":{"KOREA":"모두들 안녕하세요!","JPN":"みなさん、こんにちは！","ENG":"Hello, everyone!","TWN":"大家好！"},"stage":{"bg":"SPORTSGROUND","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_SPORTS_BG","face":"UNIT_LAUGH"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"HARIM_REBBIT_SPORTS_BG","text":{"KOREA":"올해 운동회에서 홍팀 응원과 함께 진행을 맡게 된 양하림이에요!","JPN":"今年の運動会で赤組の応援と進行役を務めることになったホシノ・ウサギです！","ENG":"I'm Yang Harim, charged with hosting this year's Field Day and cheering for the Red Team.","TWN":"我是在今年運動會上支持紅隊的主持人楊夏琳！"},"stage":{"bg":"SPORTSGROUND","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_SPORTS_BG","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"HARIM_REBBIT_SPORTS_BG","text":{"KOREA":"꼬리잡기의 룰은 간단해요! 서로 다른 선수의 허리에 달린 스카프를 떼기만 하면 되거든요!","JPN":"しっぽ取りゲームのルールは簡単です！　他の選手の腰に付いたしっぽ、つまりスカーフを取るだけ！","ENG":"The rules of Catch the Tail are simple: just remove the scarf hanging from someone else's waist!","TWN":"抓尾巴的規則非常簡單！只要搶奪不同選手綁在腰上的紗巾就可以了！"},"stage":{"bg":"SPORTSGROUND","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_SPORTS_BG","face":"UNIT_PRIDE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"HARIM_REBBIT_SPORTS_BG","text":{"KOREA":"스카프가 떨어지면 탈락! 경기 진행은 선수 중 절반의 스카프가 떨어질 때까지!","JPN":"スカーフが取られたら脱落！　試合は選手の半数のスカーフが取られるまで続きます！","ENG":"If you lose your scarf, you'll be disqualified. The game will continue until half of the players lose their scarves.","TWN":"紗巾掉落者就淘汰！半數的選手紗巾如果都掉落，就代表這場比賽結束並開始進行結果的統計！"},"stage":{"bg":"SPORTSGROUND","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_SPORTS_BG","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"HARIM_REBBIT_SPORTS_BG","text":{"KOREA":"마지막까지 남은 선수들이 모은 꼬리를 합산해서 더 많은 팀이 승리합니다!","JPN":"最後まで残った選手たちが集めたしっぽを合計して、多い方のチームが勝利となります！","ENG":"And the team whose survivors are holding the most tails wins!","TWN":"統計最後剩下的選手拿到的尾巴數量，由尾巴數量最多的隊伍獲勝！"},"stage":{"bg":"SPORTSGROUND","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_SPORTS_BG","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};